import { Given, When, Then } from '@cucumber/cucumber'
import { Actor, eventually } from '@cucumber/screenplay'

import World from '../support/World'
import { Message } from '../../src/types'
import assert from 'assert'
import getSession from '../support/helpers/getSession'

Given('{actor} is online', async function (this: World, actor: Actor<World>) {
  await actor.attemptsTo(this.startSession())
})

Given(
  '{actor} is located {int}m from {actor}',
  function (this: World, actor1: Actor<World>, distance: number, actor2: Actor<World>) {
    // We don't use a task (actor.attemptsTo) here.

    const actor1Session = this.shouty.getSession(getSession(actor1).userId)
    const actor2Session = this.shouty.getSession(getSession(actor2).userId)
    actor1Session.coordinate = { x: actor2Session.coordinate.x, y: actor2Session.coordinate.y + distance }
  }
)

When('{actor} shouts {string}', async function (this: World, shouter: Actor, message: Message) {
  await shouter.attemptsTo(this.shout(message))
  shouter.remember('lastMessage', message)
})

Then('{actor} hears {actor}’s message', async function (this: World, listener: Actor<World>, shouter: Actor) {
  const shouterLastMessage = shouter.recall('lastMessage')

  await eventually(() => {
    const listenerMessages = listener.ask(this.inboxMessages())
    assert.deepStrictEqual(listenerMessages, [shouterLastMessage])
  })
})

Then('{actor} hears nothing', async function (this: World, listener: Actor<World>) {
  await eventually(() => {
    const listenerMessages = listener.ask(this.inboxMessages())
    assert.deepStrictEqual(listenerMessages, [])
  })
})

import { Actor } from '@cucumber/screenplay'
import World from '../World'
import { Session } from '../../../src/types'
import HttpSession from '../../../src/HttpSession'
import NodeEventSource from 'eventsource'

export default function getSession(actor: Actor<World>): Session {
  return actor.recall('session', () => {
    const shoutySession = actor.world.shouty.makeSession(actor.name)

    // Make sure we stop the session at the end of each scenario
    actor.world.stops.push(() => shoutySession.stop())

    if (actor.world.parameters.sessions === 'HttpSession') {
      const httpSession = new HttpSession(
        shoutySession.userId,
        new URL(`http://localhost:${actor.world.apiPort}`),
        (url) => new NodeEventSource(url) as EventSource
      )
      // Make sure we stop the session at the end of each scenario
      actor.world.stops.push(() => httpSession.stop())
      return httpSession
    } else {
      return shoutySession
    }
  })
}

import fetch from 'node-fetch'
import { Message, Session } from './types'
import Inbox from './Inbox'

export default class HttpSession implements Session {
  public readonly inbox = new Inbox()
  private eventSource: EventSource

  constructor(
    public readonly userId: string,
    private readonly baseURL: URL,
    private readonly newEventSource: (url: string) => EventSource
  ) {}

  async start(): Promise<void> {
    const url = new URL('/messages', this.baseURL)
    url.searchParams.set('userId', this.userId)

    return new Promise((resolve, reject) => {
      const eventSource = this.newEventSource(url.toString())
      eventSource.addEventListener('message', (event) => {
        this.inbox.deliver(event.data)
      })

      eventSource.onerror = (e) => reject(new Error(`Connection failed: ${JSON.stringify(e)}`))
      eventSource.onopen = () => resolve()
      this.eventSource = eventSource
    })
  }

  async stop(): Promise<void> {
    this.eventSource.close()
  }

  async send(message: Message): Promise<void> {
    const url = new URL('/shout', this.baseURL)
    url.searchParams.set('userId', this.userId)
    url.searchParams.set('message', message)
    await fetch(url.toString(), { method: 'POST' })
  }
}

import { MessageListener, Message } from './types'

export default class Inbox {
  private readonly listeners = new Set<MessageListener>()

  on(listener: MessageListener) {
    this.listeners.add(listener)
  }

  off(listener: MessageListener) {
    this.listeners.delete(listener)
  }

  deliver(message: Message) {
    if (this.listeners.size === 0) {
      throw new Error(`Dropping message "${message}" on the floor because there are no listeners`)
    }
    for (const listener of this.listeners) {
      listener(message)
    }
  }
}

import { Actor } from '@cucumber/screenplay'
import World from '../World'
import { Message } from '../../../src/types'
import getSession from './getSession'

export default function getInboxMessages(actor: Actor<World>): readonly Message[] {
  return actor.recall('inboxMessages', () => {
    const session = getSession(actor)
    const messages: Message[] = []
    session.inbox.on((message) => messages.push(message))
    return messages
  })
}

import { Actor } from '@cucumber/screenplay'
import World from '../../World'
import { InboxMessages } from '../types'
import { microdata, toArray } from '@cucumber/microdata'
import { Conversation, Message, TextDigitalDocument } from 'schema-dts'
import { DomUser } from '../../helpers/getDomUser'
import assert from 'assert'

export const inboxMessages: InboxMessages = () => {
  return (actor: Actor<World>) => {
    const { element } = actor.recall<DomUser>('domUser')
    // https://schema.org/Conversation
    const conversation = microdata<Conversation>('https://schema.org/Conversation', element)
    assert(conversation)
    const messages = toArray<Message>(conversation.hasPart as Message | Message[])
    return messages.map((message) => (message.about as TextDigitalDocument).name as string)
  }
}

import { Actor, eventually } from '@cucumber/screenplay'
import World from '../../../World'
import { getByText } from '@testing-library/dom'
import { ClickShoutButton } from './types'
import { DomUser } from '../../../helpers/getDomUser'
import assert from 'assert'

export const clickShoutButton: ClickShoutButton = () => {
  return async (actor: Actor<World>) => {
    const { element, user } = actor.recall<DomUser>('domUser')
    const submit = getByText(element, `Shout`)
    user.click(submit)
    // The field will be cleared when the POST is complete
    await eventually(() => assert.deepStrictEqual(element.querySelector('input')?.value, ''))
  }
}

import { Actor } from '@cucumber/screenplay'
import World from '../../../World'
import { getByLabelText } from '@testing-library/dom'
import userEvent from '@testing-library/user-event'
import { TypeMessage } from './types'
import { DomUser } from '../../../helpers/getDomUser'

export const typeMessage: TypeMessage = (message) => {
  return async (actor: Actor<World>) => {
    const { element } = actor.recall<DomUser>('domUser')
    const $location = getByLabelText(element, `Message`)
    userEvent.type($location, '{selectall}' + message)
  }
}

import { Actor } from '@cucumber/screenplay'
import World from '../../World'
import { Shout } from '../types'
import { typeMessage } from './interactions/typeMessage'
import { clickShoutButton } from './interactions/clickShoutButton'

export const shout: Shout = (message) => {
  return async (actor: Actor<World>) => {
    actor.attemptsTo(typeMessage(message))
    await actor.attemptsTo(clickShoutButton())
  }
}

import { Actor } from '@cucumber/screenplay'
import { InboxMessages } from '../types'
import World from '../../World'
import getInboxMessages from '../../helpers/getInboxMessages'

export const inboxMessages: InboxMessages = () => {
  return (actor: Actor<World>) => {
