import { Actor } from '@cucumber/screenplay'
import World from '../../World'
import { StartSession } from '../types'
import getSession from '../../helpers/getSession'
import assert from 'assert'
import getInboxMessages from '../../helpers/getInboxMessages'

export const startSession: StartSession = () => {
  return async (actor: Actor<World>) => {
    const session = getSession(actor)
    assert.deepStrictEqual(getInboxMessages(actor), [])
    await session.start()
  }
}

import { setWorldConstructor, Before, After, defineParameterType } from '@cucumber/cucumber'
import { AppElements } from '@cucumber/electron'
import { ActorWorld, ActorParameterType } from '@cucumber/screenplay'

import Shouty from '../../src/Shouty'
import { makeApp } from '../../src/server'
import { promisify } from 'util'
import { InboxMessages, Shout, StartSession } from './tasks/types'

defineParameterType({ ...ActorParameterType })
defineParameterType({
  name: 'coordinate',
  regexp: /\(\s*(\d+),\s*(\d+)\s*\)/,
  transformer(x: string, y: string) {
    return { x: +x, y: +y }
  },
})

type Stop = () => Promise<void>

export default class World extends ActorWorld {
  public readonly stops: Stop[] = []
  public readonly shouty = new Shouty()
  public readonly apiPort = 8087

  public readonly appElements = new AppElements()

  // Tasks
  public startSession: StartSession
  public shout: Shout
  public inboxMessages: InboxMessages
}

setWorldConstructor(World)

Before(async function (this: World) {
  if (!process.env.KEEP_DOM) {
    this.stops.push(async () => this.appElements.destroyAll())
  }

  if (this.parameters.sessions === 'HttpSession') {
    const app = makeApp(this.shouty)

    await new Promise<void>((resolve, reject) => {
      app.on('error', reject)

      const server = app.listen(this.apiPort, resolve)
      const stopServer = promisify(server.close.bind(server)) as Stop
      this.stops.push(stopServer)
    })
  }
})

After(async function (this: World) {
  await Promise.all(this.stops.reverse().map((stop) => stop()))
})

import calculateDistance from './calculateDistance'
import { Message, Session } from './types'
import ShoutySession from './ShoutySession'
import Inbox from './Inbox'

export default class Shouty {
  private readonly sessionByUserId = new Map<string, ShoutySession>()

  makeSession(userId: string): Session {
    let session = this.sessionByUserId.get(userId)
    if (!session) {
      const inbox = new Inbox()
      session = new ShoutySession(userId, inbox, this)
      this.sessionByUserId.set(userId, session)
    }
    return session
  }

  getSession(userId: string): ShoutySession {
    const session = this.sessionByUserId.get(userId)
    if (!session) {
      throw new Error(`No session for userId=${userId}`)
    }
    return session
  }

  broadcast(fromSession: ShoutySession, message: Message) {
    for (const session of this.sessionByUserId.values()) {
      const distance = calculateDistance(fromSession.coordinate, session.coordinate)
      if (distance <= 1000) {
        session.inbox.deliver(message)
      }
    }
  }
}

import { Coordinate } from './types'

export default function calculateDistance(a: Coordinate, b: Coordinate): number {
  const xDiff = Math.abs(a.x - b.x)
  const yDiff = Math.abs(a.y - b.y)
  return Math.sqrt(Math.pow(xDiff, 2) + Math.pow(yDiff, 2))
}

import { Coordinate, Message, Session } from './types'
import Shouty from './Shouty'
import Inbox from './Inbox'

export default class ShoutySession implements Session {
  public coordinate: Coordinate = { x: 0, y: 0 }

  constructor(
    public readonly userId: string,
    public readonly inbox: Inbox,
    // Members not on the Session interface
    private readonly shouty: Shouty
  ) {}

  start(): Promise<void> {
    return Promise.resolve(undefined)
  }

  stop(): Promise<void> {
    return Promise.resolve(undefined)
  }

  async send(message: Message): Promise<void> {
    this.shouty.broadcast(this, message)
  }
}

import express from 'express'
import Shouty from './Shouty'
import { Message } from './types'
import SseStream from 'ssestream'

export function makeApp(shouty: Shouty) {
  const exp = express()

  exp.post('/shout', (req, res) => {
    // TODO: Get userId from JWT
    const { userId, message } = req.query

    const session = shouty.getSession(userId as string)
    session
      .send(message as Message)
      .then(() => res.status(200).end())
      .catch((err) => res.status(500).end(err.message))
  })

  exp.get('/messages', (req, res) => {
    // TODO: Get userId from JWT
    const { userId } = req.query
    const session = shouty.getSession(userId as string)
    if (!session) {
      res.status(500).end(`No session for userId=${userId}`)
      return
    }
    const sse = new SseStream(req)

    session.inbox.on((message) =>
      sse.writeMessage({
        event: 'message',
        data: message,
      })
    )

    sse.pipe(res)

    req.on('close', () => {
      sse.unpipe(res)
      res.end()
    })
  })

  return exp
}
